<span class="line"><span style="color:#9399B2;">                &quot;</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;[package]</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">name = </span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">coding-agent</span><span style="color:#F5C2E7;">\\&quot;\\n</span><span style="color:#A6E3A1;">version = </span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">0.14.0</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">&quot;</span></span>
